import React, { useEffect } from 'react';
import './Navbar.css';
import { BrowserRouter as Router, Route, NavLink, Switch } from 'react-router-dom';
import Home from '../Home/Home';
import Projects from '../Projects/Projects';
import PageNotFound from '../404/404';


function Navbar () {
  useEffect(() => {
    const navbar = document.getElementById("navbar");
    const navbarToggle = navbar.querySelector(".navbar-toggle");
    function openMobileNavbar () {
      navbar.classList.add("opened");
      navbarToggle.setAttribute("aria-label", "Close navigation menu.");
    }
    function closeMobileNavbar () {
      navbar.classList.remove("opened");
      navbarToggle.setAttribute("aria-label", "Open navigation menu.");
    }
    navbarToggle.addEventListener("click", () => {
      if (navbar.classList.contains("opened")) {
        closeMobileNavbar();
      } else {
        openMobileNavbar();
      }
    });
    const navbarMenu = navbar.querySelector(".navbar-menu");
    const navbarLinksContainer = navbar.querySelector(".navbar-links");
    navbarLinksContainer.addEventListener("click", (clickEvent) => {
      clickEvent.stopPropagation();
    });
    navbarMenu.addEventListener("click", closeMobileNavbar);
  }, []);
  return (
    <Router basename="stavzdev.xyz">
      <header id="navbar">
        <nav className="navbar-container container">
          <a href="/" className="home-link">
            <img className="navbar-logo" src="https://avatars.githubusercontent.com/u/36641973?v=4" alt="logo"></img>
            StavZDev
          </a>
          <button type="button" className="navbar-toggle" aria-label="Open navigation menu">
            <span className="icon-bar"></span>
            <span className="icon-bar"></span>
            <span className="icon-bar"></span>
          </button>
          <div className="navbar-menu">
            <ul className="navbar-links">
              <li className="navbar-item"><NavLink className="navbar-link" to="/" exact>Home</NavLink></li>
              <li className="navbar-item"><NavLink className="navbar-link" to="/projects">Projects</NavLink></li>
            </ul>
          </div>
        </nav>
      </header>
      <Switch>
        <Route exact path='/' component={Home}></Route>
        <Route path='/projects' component={Projects}></Route>
        <Route component={PageNotFound}></Route>
      </Switch>
    </Router>
  );
}
export default Navbar;